 38→void ULFPMapEditorComponent::ToggleEditorMode()
 39→{
 40→	bEditorActive = !bEditorActive;
 41→
 42→	if (!bEditorActive)
 43→	{
 44→		CurrentTool = ELFPMapEditorTool::MET_None;
 45→	}
 46→
 47→	OnEditorModeChanged.Broadcast(bEditorActive);
 48→	UE_LOG(LogTemp, Log, TEXT("地图编辑器: %s"), bEditorActive ? TEXT("开启") : TEXT("关闭"));
