 98→void ULFPMapEditorComponent::ApplyToolToCoord(int32 Q, int32 R)
 99→{
100→	if (!bEditorActive) return;
101→
102→	ALFPHexGridManager* GM = GetGridManager();
103→	if (!GM) return;
104→
105→	if (CurrentTool == ELFPMapEditorTool::MET_AddTile)
106→	{
107→		GM->AddTile(Q, R);
108→	}
109→}
