111→bool ULFPMapEditorComponent::SaveMap(const FString& FileName)
112→{
113→	ALFPHexGridManager* GM = GetGridManager();
114→	if (!GM) return false;
115→
116→	FString FullPath = GetMapSaveDirectory() / FileName + TEXT(".csv");
117→	return GM->SaveMapToCSV(FullPath);
118→}
