143→void ULFPMapEditorComponent::NewMap(int32 Width, int32 Height)
144→{
145→	ALFPHexGridManager* GM = GetGridManager();
146→	if (!GM) return;
147→
148→	GM->GenerateGrid(Width, Height);
149→	UE_LOG(LogTemp, Log, TEXT("新建地图: %dx%d"), Width, Height);
150→}
