 10→
 11→	// 绑定工具按钮
 12→	if (TerrainToolButton) TerrainToolButton->OnClicked.AddDynamic(this, &ULFPMapEditorWidget::OnTerrainToolClicked);
 13→	if (DecorationToolButton) DecorationToolButton->OnClicked.AddDynamic(this, &ULFPMapEditorWidget::OnDecorationToolClicked);
 14→	if (SpawnPointToolButton) SpawnPointToolButton->OnClicked.AddDynamic(this, &ULFPMapEditorWidget::OnSpawnPointToolClicked);
 15→	if (EventToolButton) EventToolButton->OnClicked.AddDynamic(this, &ULFPMapEditorWidget::OnEventToolClicked);
 16→	if (AddTileToolButton) AddTileToolButton->OnClicked.AddDynamic(this, &ULFPMapEditorWidget::OnAddTileToolClicked);
 17→	if (RemoveTileToolButton) RemoveTileToolButton->OnClicked.AddDynamic(this, &ULFPMapEditorWidget::OnRemoveTileToolClicked);
 18→
 19→	// 绑定参数下拉框
 20→	if (TerrainTypeComboBox) TerrainTypeComboBox->OnSelectionChanged.AddDynamic(this, &ULFPMapEditorWidget::OnTerrainTypeChanged);
 21→	if (DecorationComboBox) DecorationComboBox->OnSelectionChanged.AddDynamic(this, &ULFPMapEditorWidget::OnDecorationIDChanged);
 22→	if (SpawnFactionComboBox) SpawnFactionComboBox->OnSelectionChanged.AddDynamic(this, &ULFPMapEditorWidget::OnSpawnFactionChanged);
 23→
 24→	// 绑定保存/加载按钮
 25→	if (SaveButton) SaveButton->OnClicked.AddDynamic(this, &ULFPMapEditorWidget::OnSaveClicked);
 26→	if (LoadButton) LoadButton->OnClicked.AddDynamic(this, &ULFPMapEditorWidget::OnLoadClicked);
 27→	if (NewMapButton) NewMapButton->OnClicked.AddDynamic(this, &ULFPMapEditorWidget::OnNewMapClicked);
 28→
 29→	// 填充地形类型下拉框
 30→	if (TerrainTypeComboBox)
 31→	{
 32→		TerrainTypeComboBox->ClearOptions();
 33→		TerrainTypeComboBox->AddOption(TEXT("TT_Grass"));
 34→		TerrainTypeComboBox->AddOption(TEXT("TT_Sand"));
 35→		TerrainTypeComboBox->AddOption(TEXT("TT_Dirt"));
 36→		TerrainTypeComboBox->AddOption(TEXT("TT_Stone"));
 37→		TerrainTypeComboBox->AddOption(TEXT("TT_Snow"));
 38→		TerrainTypeComboBox->AddOption(TEXT("TT_Water"));
 39→		TerrainTypeComboBox->AddOption(TEXT("TT_Lava"));
 40→		TerrainTypeComboBox->AddOption(TEXT("TT_Magic"));
 41→		TerrainTypeComboBox->AddOption(TEXT("TT_Bridge"));
 42→		TerrainTypeComboBox->SetSelectedOption(TEXT("TT_Grass"));
 43→	}
 44→
 45→	// 填充出生点阵营下拉框
 46→	if (SpawnFactionComboBox)
 47→	{
 48→		SpawnFactionComboBox->ClearOptions();
 49→		SpawnFactionComboBox->AddOption(TEXT("SF_None"));
 50→		SpawnFactionComboBox->AddOption(TEXT("SF_Player"));
 51→		SpawnFactionComboBox->AddOption(TEXT("SF_Enemy"));
 52→		SpawnFactionComboBox->AddOption(TEXT("SF_Neutral"));
 53→		SpawnFactionComboBox->SetSelectedOption(TEXT("SF_Player"));
 54→	}
