104→
105→	// 字符串映射到枚举
106→	static const TMap<FString, ELFPTerrainType> TerrainMap = {
107→		{TEXT("TT_Grass"), ELFPTerrainType::TT_Grass},
108→		{TEXT("TT_Sand"), ELFPTerrainType::TT_Sand},
109→		{TEXT("TT_Dirt"), ELFPTerrainType::TT_Dirt},
110→		{TEXT("TT_Stone"), ELFPTerrainType::TT_Stone},
111→		{TEXT("TT_Snow"), ELFPTerrainType::TT_Snow},
112→		{TEXT("TT_Water"), ELFPTerrainType::TT_Water},
113→		{TEXT("TT_Lava"), ELFPTerrainType::TT_Lava},
114→		{TEXT("TT_Magic"), ELFPTerrainType::TT_Magic},
115→		{TEXT("TT_Bridge"), ELFPTerrainType::TT_Bridge},
116→	};
117→
118→	if (const ELFPTerrainType* Found = TerrainMap.Find(SelectedItem))
119→	{
120→		EditorComponent->SetBrushTerrainType(*Found);
121→	}
122→}
