149→void ULFPMapEditorWidget::OnSaveClicked()
150→{
151→	if (!EditorComponent || !FileNameInput) return;
152→
153→	FString FileName = FileNameInput->GetText().ToString();
154→	if (FileName.IsEmpty())
155→	{
156→		UE_LOG(LogTemp, Warning, TEXT("地图编辑器: 请输入文件名"));
157→		return;
158→	}
159→
160→	if (EditorComponent->SaveMap(FileName))
161→	{
162→		UE_LOG(LogTemp, Log, TEXT("地图编辑器: 保存成功 - %s"), *FileName);
163→	}
