191→void ULFPMapEditorWidget::UpdateToolIndicator(ELFPMapEditorTool NewTool)
192→{
193→	if (!CurrentToolText) return;
194→
195→	static const TMap<ELFPMapEditorTool, FString> ToolNames = {
196→		{ELFPMapEditorTool::MET_None, TEXT("无")},
197→		{ELFPMapEditorTool::MET_Terrain, TEXT("地形笔刷")},
198→		{ELFPMapEditorTool::MET_Decoration, TEXT("装饰笔刷")},
199→		{ELFPMapEditorTool::MET_SpawnPoint, TEXT("出生点")},
200→		{ELFPMapEditorTool::MET_Event, TEXT("事件标签")},
201→		{ELFPMapEditorTool::MET_AddTile, TEXT("添加格子")},
202→		{ELFPMapEditorTool::MET_RemoveTile, TEXT("移除格子")},
203→	};
204→
205→	if (const FString* Name = ToolNames.Find(NewTool))
206→	{
207→		CurrentToolText->SetText(FText::FromString(*Name));
208→	}
209→}
