229→// 选择完成
230→void ALFPTacticsPlayerController::OnSelectCompleted(const FInputActionValue& Value)
231→{
232→    if (!bIsSelecting) return;
233→    bIsSelecting = false;
234→
235→    // 获取鼠标位置
236→    float MouseX, MouseY;
237→    GetMousePosition(MouseX, MouseY);
238→    FVector2D SelectionEnd = FVector2D(MouseX, MouseY);
239→
240→    // 简单的点击检测（非拖拽）
241→    if (FVector2D::Distance(SelectionStart, SelectionEnd) < 10.0f)
242→    {
243→        FHitResult HitResult;
244→        GetHitResultAtScreenPosition(SelectionEnd, ECC_Visibility, false, HitResult);
245→
246→        if (HitResult.bBlockingHit)
247→        {
248→            // 尝试选中单位
249→            ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(HitResult.GetActor());
250→            if (Unit)
251→            {
252→                SelectUnit(Unit);
253→                return;
254→            }
255→
256→            // 尝试选中格子
257→            ALFPHexTile* Tile = Cast<ALFPHexTile>(HitResult.GetActor());
258→            if (Tile)
259→            {
260→                SelectTile(Tile);
261→                return;
262→            }
263→        }
264→    }
265→}
