176→void ALFPHexGridManager::LoadMapFromDataTable(UDataTable* InMapData)
177→{
178→	if (!InMapData)
179→	{
180→		UE_LOG(LogTemp, Warning, TEXT("LoadMapFromDataTable: DataTable 为空"));
181→		return;
182→	}
183→
184→	ClearGrid();
185→
186→	TArray<FLFPMapTileRow*> AllRows;
187→	InMapData->GetAllRows<FLFPMapTileRow>(TEXT("LoadMap"), AllRows);
188→
189→	for (const FLFPMapTileRow* Row : AllRows)
190→	{
191→		if (Row)
192→		{
193→			SpawnTileAt(Row->Q, Row->R, Row->TerrainType,
194→				Row->DecorationID, Row->SpawnFaction, Row->SpawnIndex, Row->EventTag);
195→		}
196→	}
197→
198→	UE_LOG(LogTemp, Log, TEXT("LoadMapFromDataTable: 加载了 %d 个格子"), AllRows.Num());
199→}
