281→TArray<FLFPMapTileRow> ALFPHexGridManager::ExportMapData() const
282→{
283→	TArray<FLFPMapTileRow> Result;
284→	for (const auto& Pair : GridMap)
285→	{
286→		ALFPHexTile* Tile = Pair.Value;
287→		if (!Tile) continue;
288→
289→		FLFPMapTileRow Row;
290→		FLFPHexCoordinates Coord = Tile->GetCoordinates();
291→		Row.Q = Coord.Q;
292→		Row.R = Coord.R;
293→		Row.TerrainType = Tile->GetTerrainData() ? Tile->GetTerrainData()->TerrainType : ELFPTerrainType::TT_Grass;
294→		Row.DecorationID = Tile->DecorationID;
295→		Row.SpawnFaction = Tile->SpawnFaction;
296→		Row.SpawnIndex = Tile->SpawnIndex;
297→		Row.EventTag = Tile->EventTag;
298→		Result.Add(Row);
299→	}
300→	return Result;

